#include <cuda_runtime.h>
#include <cstdio>
#include <cstdint>
#include <cstddef>
#include <cstdlib>
#include <algorithm>
#include <cstring>

__global__ void measure_dram_latency(volatile uint32_t* indices, uint64_t* cycles, size_t size) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;

    uint32_t idx = 0;
    asm volatile("" : : : "memory");

    volatile uint64_t start = clock64();
    #pragma unroll 1
    for (uint64_t i = 0; i < 10000000; i++) {
        idx = indices[idx];
    }
    volatile uint64_t end = clock64();

    asm volatile("" : : : "memory");

    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");

    *cycles = (end - start) / 10000000;
}

void generate_random_permutation(uint32_t* indices, size_t size) {
    // Initialize sequential indices
    for (size_t i = 0; i < size; i++) {
        indices[i] = i;
    }

    // Fisher-Yates shuffle with LCG
    uint32_t seed = 12345;
    for (size_t i = size - 1; i > 0; i--) {
        seed = seed * 1664525 + 1013904223;
        uint32_t j = seed % (i + 1);

        uint32_t temp = indices[i];
        indices[i] = indices[j];
        indices[j] = temp;
    }
}

int main() {
    const size_t size = 32 * 1024 * 1024; // 32M elements = 128 MB
    const int trials = 3;
    uint64_t results[trials];

    // Allocate host memory
    uint32_t* h_indices = (uint32_t*)malloc(size * sizeof(uint32_t));

    // Generate random permutation
    generate_random_permutation(h_indices, size);

    // Allocate device memory
    uint32_t* d_indices;
    uint64_t* d_cycles;
    cudaMalloc(&d_indices, size * sizeof(uint32_t));
    cudaMalloc(&d_cycles, sizeof(uint64_t));

    // Copy indices to device
    cudaMemcpy(d_indices, h_indices, size * sizeof(uint32_t), cudaMemcpyHostToDevice);

    // Run trials
    for (int trial = 0; trial < trials; trial++) {
        measure_dram_latency<<<1, 1>>>(d_indices, d_cycles, size);
        cudaDeviceSynchronize();

        uint64_t cycles;
        cudaMemcpy(&cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);
        results[trial] = cycles;
    }

    // Calculate median
    std::sort(results, results + trials);
    uint64_t median_cycles = results[trials / 2];

    printf("dram_latency_cycles: %lu\n", median_cycles);

    // Cleanup
    free(h_indices);
    cudaFree(d_indices);
    cudaFree(d_cycles);

    return 0;
}

  #include <cuda_runtime.h>
  #include <cstdio>
  #include <cstdint>
  #include <cstddef>
  #include <cstdlib>
  #include <algorithm>    // for std::sort (median calculation)
  #include <cstring>      // for memset

__global__ void cache_sweep_kernel(volatile float* data, volatile uint64_t* cycles, size_t size) {
    if (threadIdx.x != 0 || blockIdx.x != 0) return;  // Single thread

    uint64_t idx = 0;
    asm volatile("" : : : "memory");  // Compiler barrier before timing

    volatile uint64_t start = clock64();
    #pragma unroll 1
    for (uint64_t i = 0; i < 1000000; i++) {
        idx = (idx + 1) % size;
        float val = data[idx];
        asm volatile("");
    }
    volatile uint64_t end = clock64();

    asm volatile("" : : : "memory");  // Compiler barrier after timing
    volatile uint64_t sink64 = (uint64_t)idx;
    asm volatile("" : "+l"(sink64) : : "memory");
    *cycles = (end - start) / 1000000;  // Average cycles per access
}

int main() {
    const size_t max_size_mb = 64;
    const size_t min_size_mb = 1;
    const size_t step_mb = 1;

    // Find the inflection point where latency increases dramatically
    float* h_data = new float[max_size_mb * 256 * 1024];  // 4 bytes per float
    float* d_data;
    cudaMalloc(&d_data, max_size_mb * 256 * 1024 * sizeof(float));

    // Initialize host data
    for (size_t i = 0; i < max_size_mb * 256 * 1024; i++) {
        h_data[i] = 1.0f;
    }

    // Copy to device
    cudaMemcpy(d_data, h_data, max_size_mb * 256 * 1024 * sizeof(float), cudaMemcpyHostToDevice);

    uint64_t* d_cycles;
    cudaMalloc(&d_cycles, sizeof(uint64_t));

    // Sweep through different working set sizes
    float prev_latency = 0.0f;
    size_t cache_size_mb = max_size_mb;

    for (size_t size_mb = min_size_mb; size_mb <= max_size_mb; size_mb += step_mb) {
        size_t size_floats = size_mb * 256 * 1024;  // 256K floats per MB

        // Launch kernel
        cache_sweep_kernel<<<1, 1>>>(d_data, d_cycles, size_floats);
        cudaDeviceSynchronize();

        uint64_t cycles;
        cudaMemcpy(&cycles, d_cycles, sizeof(uint64_t), cudaMemcpyDeviceToHost);

        float latency = (float)cycles;

        // Detect inflection point (dramatic latency increase)
        if (prev_latency > 0 && latency > prev_latency * 1.5f && cache_size_mb == max_size_mb) {
            cache_size_mb = size_mb - step_mb;
        }

        prev_latency = latency;
    }

    printf("l2_cache_size_mb: %zu\n", cache_size_mb);

    // Cleanup
    cudaFree(d_data);
    cudaFree(d_cycles);
    delete[] h_data;

    return 0;
}
